func TestEntitySerialization_Roundtrip(t *testing.T) {
	// Test that entity can be marshaled and unmarshaled without data loss

	original := &graph.EntityState{
		ID: "c360.platform.robotics.mav1.drone.001",
		Triples: []message.Triple{
			{
				Subject:    "c360.platform.robotics.mav1.drone.001",
				Predicate:  "robotics.status.armed",
				Object:     true,
				Confidence: 1.0,
				Context:    "sensor.data",
				Timestamp:  time.Now().Truncate(time.Millisecond), // Truncate to avoid precision issues
			},
			{
				Subject:    "c360.platform.robotics.mav1.drone.001",
				Predicate:  "robotics.battery.level",
				Object:     85.5,
				Confidence: 0.95,
				Context:    "sensor.data",
				Timestamp:  time.Now().Truncate(time.Millisecond),
			},
		},
		Version:   1,
		UpdatedAt: time.Now().Truncate(time.Millisecond),
	}

	// Marshal
	data, err := json.Marshal(original)
	require.NoError(t, err, "marshal should succeed")

	// Unmarshal
	var restored graph.EntityState
	err = json.Unmarshal(data, &restored)
	require.NoError(t, err, "unmarshal should succeed")

	// Verify all fields match
	assert.Equal(t, original.ID, restored.ID, "entity ID should match")
	assert.Equal(t, original.Version, restored.Version, "version should match")
	assert.Equal(t, original.UpdatedAt.Unix(), restored.UpdatedAt.Unix(), "timestamp should match (second precision)")
	assert.Len(t, restored.Triples, len(original.Triples), "triple count should match")

	// Verify triples
	for i, triple := range original.Triples {
		assert.Equal(t, triple.Subject, restored.Triples[i].Subject, "triple %d subject should match", i)
		assert.Equal(t, triple.Predicate, restored.Triples[i].Predicate, "triple %d predicate should match", i)
		assert.Equal(t, triple.Object, restored.Triples[i].Object, "triple %d object should match", i)
		assert.Equal(t, triple.Confidence, restored.Triples[i].Confidence, "triple %d confidence should match", i)
		assert.Equal(t, triple.Context, restored.Triples[i].Context, "triple %d context should match", i)
	}
}

